#include "interface.h"
#include <yyjson.h>

uint64_t compute_checksum(const std::string& json_input) {
  yyjson_doc* doc = yyjson_read(json_input.data(), json_input.size(), 0);
  if (!doc) return 0;
  yyjson_val* root = yyjson_doc_get_root(doc);
  uint64_t sum = 0;
  size_t idx, max;
  yyjson_val *item, *id, *nested, *a, *b;
  yyjson_arr_iter_iterate(yyjson_doc_get_root(doc), &idx, &max, &item);
  while (item) {
    id = yyjson_obj_get(item, "id");
    nested = yyjson_obj_get(item, "nested");
    a = yyjson_obj_get(nested, "a");
    b = yyjson_obj_get(nested, "b");
    if (id && yyjson_is_uint(id)) sum += yyjson_get_uint(id);
    if (a && yyjson_is_uint(a)) sum += yyjson_get_uint(a);
    if (b && yyjson_is_uint(b)) sum += yyjson_get_uint(b);
    item = yyjson_arr_iter_next(&idx, &max, item);
  }
  yyjson_doc_free(doc);
  return sum;
}
